import createClient, { type Client } from 'openapi-fetch'
import type { paths } from '~~/shared/types/api.gen'

// Module-scoped singleton so every consumer shares the same auth + onResponse
// pipeline. Nuxt SSR isolates module state per-request via the `nitro:close`
// boundary, so this doesn't bleed between users.
let _client: Client<paths> | null = null

/**
 * Typed Heya API client backed by openapi-fetch + the spec we generate from
 * the Go server (see web/shared/types/api.gen.ts, regenerated by
 * `make gen-api-client`).
 *
 * Use this for new code. Legacy `useApi()` / `apiFetch()` continue to work
 * for existing call sites — migrate incrementally.
 *
 * Auto-attaches `Authorization: Bearer <token>` from useAuth() and logs the
 * user out on 401 so existing UX (redirect to /login) keeps working.
 */
export function useApiClient(): Client<paths> {
  if (_client) return _client

  _client = createClient<paths>({ baseUrl: '' })

  _client.use({
    onRequest({ request }) {
      const { token } = useAuth()
      if (token.value) {
        request.headers.set('Authorization', `Bearer ${token.value}`)
      }
      return request
    },
    onResponse({ response }) {
      if (response.status === 401) {
        useAuth().logout()
      }
      return response
    },
  })

  return _client
}
